// Load config files from disk
const fs = require('fs');

const roleFilters = JSON.parse(
  fs.readFileSync(process.env.ROLE_FILTERS_PATH || '/Users/YOURNAME/Projects/job-scraper/config/role_filters.json', 'utf8')
);
const locationPolicy = JSON.parse(
  fs.readFileSync(process.env.LOCATION_POLICY_PATH || '/Users/YOURNAME/Projects/job-scraper/config/location_policy.json', 'utf8')
);
const companiesConfig = JSON.parse(
  fs.readFileSync(process.env.TARGET_COMPANIES_PATH || '/Users/YOURNAME/Projects/job-scraper/config/target_companies.json', 'utf8')
);

const companyMap = {};
for (const c of companiesConfig.companies) {
  companyMap[c.company_id] = c;
}

return [{ json: { roleFilters, locationPolicy, companyMap } }];

// Normalize and score each raw job item.
// Paste normalize.js functions inline here for n8n Code node execution.

const crypto = require('crypto');

function computeJobKey(companyId, postingId) {
  return crypto.createHash('sha256').update(`${companyId}::${postingId}`).digest('hex');
}

function normalizeTitle(raw) {
  return (raw || '').toLowerCase()
    .replace(/\(.*?\)/g, '').replace(/\[.*?\]/g, '')
    .replace(/req#?\s*\d+/gi, '').replace(/[-–—|]/g, ' ')
    .replace(/\s+/g, ' ').trim();
}

function extractPostingId(url, pageId) {
  if (pageId) return String(pageId).trim();
  const patterns = [
    /\/jobs?\/([\d]+)/i, /[?&](?:job_?id|jobId|req_?id)=([^&]+)/i,
    /lever\.co\/\w+\/([^/?]+)/i, /gh\/(\d+)/i
  ];
  for (const p of patterns) { const m = url.match(p); if (m) return m[1]; }
  return crypto.createHash('sha256').update(url).digest('hex').slice(0, 16);
}

function normalizeLocation(raw, policy) {
  if (!raw) return 'unknown';
  const lower = raw.toLowerCase();
  const check = (labels) => labels.some(l => lower.includes(l.toLowerCase()));
  if (check(policy.hard_reject_if_only) && !check(policy.remote_labels) &&
      !check(policy.austin_metro_labels) && !check(policy.san_antonio_metro_labels)) return 'rejected';
  if (check(policy.remote_labels)) return 'remote';
  if (check(policy.austin_metro_labels)) return 'austin_metro';
  if (check(policy.san_antonio_metro_labels)) return 'san_antonio_metro';
  if (check(policy.ambiguous_triggers)) return 'unknown';
  return 'rejected';
}

function detectTerm(title, desc, filters) {
  const h = `${title} ${desc || ''}`.toLowerCase();
  return filters.require_term.some(t => h.includes(t.toLowerCase())) ? 'fall_2026' : null;
}

function detectType(title, desc, filters) {
  const h = `${title} ${desc || ''}`.toLowerCase();
  return filters.require_type.some(t => h.includes(t.toLowerCase()));
}

function detectRoleFamily(titleNorm, desc, filters) {
  const h = `${titleNorm} ${desc || ''}`.toLowerCase();
  for (const [family, cfg] of Object.entries(filters.role_families)) {
    if (cfg.exclusions.some(ex => h.includes(ex.toLowerCase()))) continue;
    const matched = cfg.title_keywords.filter(kw => h.includes(kw.toLowerCase()));
    if (matched.length > 0) return { family, matched };
  }
  return null;
}

function hasGlobalExclusion(titleNorm, filters) {
  return filters.global_exclusions.some(ex => titleNorm.includes(ex.toLowerCase()));
}

// ---- Main ----
const rawJobs = $input.all().map(i => i.json);
const config = $('Load Config').first().json;
const { roleFilters, locationPolicy, companyMap } = config;

const results = [];

for (const raw of rawJobs) {
  if (raw._needs_browser) {
    results.push({ json: { ...raw, status: 'needs_attention', filter_reason: 'browser_required' } });
    continue;
  }

  const company = companyMap[raw.company_id] || { company_id: raw.company_id, tier: 5 };
  const titleNorm = normalizeTitle(raw.title);
  const postingId = extractPostingId(raw.url || '', raw.posting_id);
  const jobKey = computeJobKey(raw.company_id, postingId);
  const locationNorm = normalizeLocation(raw.location, locationPolicy);

  if (locationNorm === 'rejected') {
    results.push({ json: { job_key: jobKey, posting_id: postingId, company_id: raw.company_id,
      title_raw: raw.title, title_normalized: titleNorm, location_raw: raw.location,
      location_normalized: locationNorm, source: raw.source || 'careers_page',
      source_url: raw.url || '', term: null, role_family: null, match_tags: '[]',
      match_score: 0, status: 'filtered_out', filter_reason: `location_rejected: "${raw.location}"` } });
    continue;
  }

  if (hasGlobalExclusion(titleNorm, roleFilters)) {
    results.push({ json: { job_key: jobKey, posting_id: postingId, company_id: raw.company_id,
      title_raw: raw.title, title_normalized: titleNorm, location_raw: raw.location,
      location_normalized: locationNorm, source: raw.source || 'careers_page',
      source_url: raw.url || '', term: null, role_family: null, match_tags: '[]',
      match_score: 0, status: 'filtered_out', filter_reason: 'global_exclusion_in_title' } });
    continue;
  }

  if (!detectType(raw.title, raw.description, roleFilters)) {
    results.push({ json: { job_key: jobKey, posting_id: postingId, company_id: raw.company_id,
      title_raw: raw.title, title_normalized: titleNorm, location_raw: raw.location,
      location_normalized: locationNorm, source: raw.source || 'careers_page',
      source_url: raw.url || '', term: null, role_family: null, match_tags: '[]',
      match_score: 0, status: 'filtered_out', filter_reason: 'not_internship' } });
    continue;
  }

  const term = detectTerm(raw.title, raw.description, roleFilters);
  if (!term) {
    results.push({ json: { job_key: jobKey, posting_id: postingId, company_id: raw.company_id,
      title_raw: raw.title, title_normalized: titleNorm, location_raw: raw.location,
      location_normalized: locationNorm, source: raw.source || 'careers_page',
      source_url: raw.url || '', term: null, role_family: null, match_tags: '[]',
      match_score: 0, status: 'filtered_out', filter_reason: 'wrong_term' } });
    continue;
  }

  const familyResult = detectRoleFamily(titleNorm, raw.description, roleFilters);
  if (!familyResult) {
    results.push({ json: { job_key: jobKey, posting_id: postingId, company_id: raw.company_id,
      title_raw: raw.title, title_normalized: titleNorm, location_raw: raw.location,
      location_normalized: locationNorm, source: raw.source || 'careers_page',
      source_url: raw.url || '', term, role_family: null, match_tags: '[]',
      match_score: 0, status: 'filtered_out', filter_reason: 'no_role_family_match' } });
    continue;
  }

  const scoring = roleFilters.scoring;
  const score = scoring.title_match_weight + (scoring[`tier_${company.tier}_bonus`] || 0);
  const finalStatus = locationNorm === 'unknown' ? 'needs_attention' : 'eligible';

  results.push({ json: {
    job_key: jobKey,
    company_id: raw.company_id,
    company_display: company.display_name || raw.company_id,
    title_raw: raw.title,
    title_normalized: titleNorm,
    location_raw: raw.location || '',
    location_normalized: locationNorm,
    source: raw.source || 'careers_page',
    source_url: raw.url || '',
    posting_id: postingId,
    term,
    role_family: familyResult.family,
    match_tags: JSON.stringify(familyResult.matched),
    match_score: score,
    status: finalStatus,
    filter_reason: locationNorm === 'unknown' ? `ambiguous_location: "${raw.location}"` : null,
    first_seen_at: new Date().toISOString(),
    last_seen_at: new Date().toISOString()
  } });
}

return results;
